/**
 * Webhook Event Handler Registry
 *
 * Manages event handlers for both inbound webhooks (from external providers)
 * and app events (for outbound webhooks).
 */

import type { CloudflareBindings } from "../../env";

export interface WebhookEventContext {
  type: string;
  data: unknown;
  provider?: string;
  env: CloudflareBindings;
}

export type WebhookEventHandler = (ctx: WebhookEventContext) => Promise<void>;

// Handler registry: maps "provider:eventType" to handlers
const handlers = new Map<string, WebhookEventHandler[]>();

// Wildcard handlers: maps "provider:*" for catch-all handling
const wildcardHandlers = new Map<string, WebhookEventHandler[]>();

/**
 * Register a handler for a specific webhook event
 *
 * @param pattern - Event pattern in format "provider:eventType" (e.g., "stripe:checkout.session.completed")
 *                  Use "*" as eventType for wildcard (e.g., "stripe:*")
 * @param handler - Async function to handle the event
 *
 * @example
 * // Handle specific event
 * onWebhookEvent("stripe:checkout.session.completed", async (ctx) => {
 *   await createSubscription(ctx.data, ctx.env);
 * });
 *
 * // Handle all events from a provider
 * onWebhookEvent("stripe:*", async (ctx) => {
 *   console.log(`Received ${ctx.type} from stripe`);
 * });
 */
export function onWebhookEvent(pattern: string, handler: WebhookEventHandler): void {
  const [provider, eventType] = pattern.split(":");

  if (eventType === "*") {
    // Register wildcard handler
    const existing = wildcardHandlers.get(provider) || [];
    existing.push(handler);
    wildcardHandlers.set(provider, existing);
  } else {
    // Register specific handler
    const existing = handlers.get(pattern) || [];
    existing.push(handler);
    handlers.set(pattern, existing);
  }
}

/**
 * Dispatch an event to all registered handlers
 *
 * @param provider - Provider name (e.g., "stripe")
 * @param type - Event type (e.g., "checkout.session.completed")
 * @param data - Event data
 * @param env - Cloudflare environment bindings
 */
export async function dispatchEvent(
  provider: string,
  type: string,
  data: unknown,
  env: CloudflareBindings
): Promise<void> {
  const ctx: WebhookEventContext = { type, data, provider, env };
  const errors: Error[] = [];

  // Get specific handlers
  const key = `${provider}:${type}`;
  const specificHandlers = handlers.get(key) || [];

  // Get wildcard handlers
  const wildcards = wildcardHandlers.get(provider) || [];

  // Combine all handlers
  const allHandlers = [...specificHandlers, ...wildcards];

  if (allHandlers.length === 0) {
    console.log(`No handlers registered for ${key}`);
    return;
  }

  // Execute all handlers (in parallel for performance)
  await Promise.all(
    allHandlers.map(async (handler) => {
      try {
        await handler(ctx);
      } catch (error) {
        console.error(`Handler error for ${key}:`, error);
        errors.push(error instanceof Error ? error : new Error(String(error)));
      }
    })
  );

  // If any handler failed, throw the first error
  if (errors.length > 0) {
    throw errors[0];
  }
}

/**
 * Check if any handlers are registered for an event
 */
export function hasHandlers(provider: string, type: string): boolean {
  const key = `${provider}:${type}`;
  const specificHandlers = handlers.get(key) || [];
  const wildcards = wildcardHandlers.get(provider) || [];
  return specificHandlers.length > 0 || wildcards.length > 0;
}

/**
 * Get all registered event patterns
 */
export function getRegisteredPatterns(): string[] {
  const patterns = Array.from(handlers.keys());
  const wildcardPatterns = Array.from(wildcardHandlers.keys()).map(p => `${p}:*`);
  return [...patterns, ...wildcardPatterns];
}

/**
 * Clear all handlers (useful for testing)
 */
export function clearHandlers(): void {
  handlers.clear();
  wildcardHandlers.clear();
}

